INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '12abb198-2a13-40c8-ae49-081b0b52694a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Gas & EIP-1559 — Fees You Control vs. Fees You Don't$escape$,
  $escape$Every Ethereum transaction consumes gas — a unit measuring computational work. Post-EIP-1559, fees split into two components: the `baseFee` (burned, protocol-set, fluctuates per block based on utilization) and the `maxPriorityFeePerGas` (your tip to the validator). You set `maxFeePerGas` as a ceiling — actual cost is `baseFee + priorityFee`, never exceeding your max. The `gasLimit` caps how much gas a transaction may consume; unused gas is refunded, but if execution exceeds the limit, the tx reverts and you still pay for work done. Use `eth_feeHistory` to sample recent base fees and build dynamic tip estimates instead of hardcoding. For contracts, reduce gas via tight packing of storage slots (`uint128` pairs share one slot), preferring `calldata` over `memory` for read-only function args, and caching `SLOAD` results in local variables — each cold `SLOAD` costs 2,100 gas vs. 100 for warm. `block.basefee` is accessible in Solidity since 0.8.7 for on-chain fee-aware logic.$escape$,
  $escape$import { createPublicClient, http, parseGwei } from 'viem';
import { mainnet } from 'viem/chains';

const client = createPublicClient({ chain: mainnet, transport: http() });

// Sample last 5 blocks: base fees + priority fees at 50th percentile
const feeHistory = await client.getFeeHistory({
  blockCount: 5,
  rewardPercentiles: [50],
});

const latestBase = feeHistory.baseFeePerGas.at(-1)!;
const medianTip = feeHistory.reward?.at(-1)?.[0] ?? parseGwei('1');

const maxFeePerGas = latestBase * 2n + medianTip; // 2x base buffer + tip
const maxPriorityFeePerGas = medianTip;

console.log({ maxFeePerGas, maxPriorityFeePerGas });$escape$,
  $escape$typescript$escape$,
