INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4adc1a2c-6120-48ea-aecb-666aa56bfd34',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum EVM Architecture — Opcodes, Gas, and the Data Location Hierarchy$escape$,
  $escape$The EVM is a stack-based virtual machine with a 256-bit word size. Every opcode pops and pushes values onto a max-depth-1024 stack — PUSH1 0x60 costs 3 gas and places one item; ADD pops two and pushes one for another 3 gas. Gas is deterministic: each opcode has a fixed base cost in the Yellow Paper, with dynamic surcharges for state access (SLOAD: 2100 gas cold, 100 warm via EIP-2929).

Data locations map to cost tiers. `calldata` is cheapest — read-only, passed with the transaction, costs 4 gas per zero byte and 16 per non-zero (EIP-2028). `memory` is byte-addressable, zero-initialized, and expands quadratically: cheap for small buffers, expensive past ~700 bytes. `storage` is a 32-byte key/value trie on disk — SSTORE to a cold slot costs 22,100 gas; a dirty re-write drops to 100. Misidentifying data locations is the most common gas bug in Solidity. Marking a function parameter `storage` instead of `calldata` in a `view` function wastes thousands of gas per call.$escape$,
  $escape$// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract DataLocations {
    uint256[] public stored; // storage slot 0

    // calldata: zero-copy, cheapest for read-only arrays
    function sumCalldata(uint256[] calldata data) external pure returns (uint256 total) {
        for (uint256 i; i < data.length; ++i) {
            total += data[i]; // reads directly from calldata, no memory copy
        }
    }

    // memory: mutable copy — costs more, needed when mutating
    function doubleMemory(uint256[] calldata data) external pure returns (uint256[] memory result) {
        result = new uint256[](data.length); // memory allocation
        for (uint256 i; i < data.length; ++i) {
            result[i] = data[i] * 2;
        }
    }
}$escape$,
