INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8fab42f6-de7f-4e09-bed9-cd80f331f7ba',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Internals — Accounts, Transactions, and Post-Merge PoS in One Pass$escape$,
  $escape$Ethereum has two account types: Externally Owned Accounts (EOAs), controlled by a private key with no code, and Contract Accounts, which hold EVM bytecode and storage. Both share the same state model: nonce, balance, storageRoot, codeHash — all committed to the world state trie.

A transaction from an EOA carries: nonce (replay protection), maxFeePerGas + maxPriorityFeePerGas (EIP-1559), gas limit, to, value, and data. The base fee is burned; only the priority fee goes to the validator. Access lists (EIP-2930) let you pre-warm storage slots, reducing gas for known reads.

Post-Merge, Ethereum's execution layer (EL) and consensus layer (CL) run as separate clients. The Engine API connects them — the CL drives block production via `engine_forkchoiceUpdatedV3`, and the EL executes and validates payloads. Validators stake 32 ETH, are pseudo-randomly assigned to committees, and attest to the head of the chain each epoch (32 slots × 12s). Finality arrives after two justified checkpoints via Casper FFG. There are no miners — `DIFFICULTY` opcode now returns `PREVRANDAO`, a VRF seed from the beacon chain.$escape$,
  $escape$import { createPublicClient, http, parseAbi } from 'viem';
import { mainnet } from 'viem/chains';

const client = createPublicClient({ chain: mainnet, transport: http() });

// Inspect a block: note baseFeePerGas (EIP-1559) and withdrawals (EIP-4895)
const block = await client.getBlock({ blockTag: 'finalized' });
console.log('baseFeePerGas:', block.baseFeePerGas);
console.log('withdrawals:', block.withdrawals?.length ?? 0);

// Decode account state for an EOA vs contract
const eoaNonce   = await client.getTransactionCount({ address: '0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045' });
const bytecode   = await client.getBytecode({          address: '0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2' });
console.log('EOA nonce:', eoaNonce);
console.log('WETH is contract:', !!bytecode);$escape$,
  $escape$typescript$escape$,
