INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '35b4ad5e-6046-4db0-a3c2-bfe8cc888977',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Layer 2 Scaling — Rollups, Optimistic vs ZK, and Why L1 Fees Hurt$escape$,
  $escape$Ethereum L1 executes every transaction on every full node — security through redundancy, but throughput caps at ~15 TPS and gas spikes during congestion. A single Uniswap v3 swap costs 100k–150k gas; at 30 gwei that's ~$4–12 depending on ETH price.

Rollups fix this by executing transactions off-chain and posting compressed calldata (or blobs via EIP-4844) to L1. L1 only verifies a proof or fraud window — not every opcode.

Optimistic rollups (Optimism, Arbitrum) assume transactions are valid and post state roots. A 7-day challenge window lets anyone submit a fraud proof using `eth_getProof` against the L1 state root. Cheap to post, expensive to dispute.

ZK rollups (zkSync Era, Starknet, Polygon zkEVM) generate a validity proof (SNARK/STARK) for every batch. L1 verifies the proof via a `verifier` contract — no trust, no waiting. Proving is compute-heavy but verification is O(1) gas.

EIP-4844 (Dencun upgrade) introduced blob-carrying transactions (`type 0x03`), giving rollups a dedicated ~128 KB/block data lane at ~10–100x cheaper than calldata, cutting L2 fees dramatically.$escape$,
  $escape$import { createPublicClient, http, parseAbi } from 'viem';
import { optimism } from 'viem/chains';

// Query the Optimism L2OutputOracle on L1 to see the latest committed state root
const l1Client = createPublicClient({ chain: mainnet, transport: http() });

const L2_OUTPUT_ORACLE = '0xdfe97868233d1aa22e815a266982f2cf17685a27';
const abi = parseAbi(['function latestOutputIndex() view returns (uint256)']);

const latestIndex = await l1Client.readContract({
  address: L2_OUTPUT_ORACLE,
  abi,
  functionName: 'latestOutputIndex',
});

console.log('Latest Optimism output index committed to L1:', latestIndex);$escape$,
