INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02a92eff-ba56-421a-80d0-f9dc6ea9ee99',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Optimistic Rollups — Fraud Proofs, Challenge Windows, and Why Withdrawals Take 7 Days$escape$,
  $escape$Optimistic rollups (Arbitrum, Optimism) post transaction batches to Ethereum L1 as calldata without on-chain execution — they assume validity by default. Security comes from fraud proofs: a 7-day challenge window during which any verifier can submit a fraud proof if the sequencer posted an invalid state root.

On Arbitrum, fraud proofs are interactive (multi-round bisection via the `RollupCore` contract), narrowing the dispute to a single L2 instruction executed on L1. Optimism's fault proof system (Cannon, live on mainnet since mid-2024) uses a MIPS-based single-round proof.

The 7-day withdrawal delay is a direct consequence — you must wait for the challenge window to close before `finalizeWithdrawalTransaction()` on L1 can be called. Bridges like Hop and Across exploit liquidity providers to give instant withdrawals, charging a fee in exchange for absorbing the delay risk.

For dApps, never assume L2 state is L1-finalized until the window closes. Use `portal.provenWithdrawals()` on the `OptimismPortal` contract to check withdrawal status programmatically.$escape$,
  $escape$import { createPublicClient, http } from 'viem';
import { optimism } from 'viem/chains';
import { getWithdrawals } from 'viem/op-stack';

const l1Client = createPublicClient({ chain: mainnet, transport: http() });
const l2Client = createPublicClient({ chain: optimism, transport: http() });

// Fetch L2 tx receipt and extract withdrawal messages
const receipt = await l2Client.getTransactionReceipt({ hash: l2TxHash });
const withdrawals = getWithdrawals(receipt);

// Check finalization status on L1 OptimismPortal
const status = await l1Client.readContract({
  address: '0xbEb5Fc579115071764c7423A4f12eDde41f106Ed', // OptimismPortal
  abi: optimismPortalAbi,
  functionName: 'finalizedWithdrawals',
  args: [withdrawals[0].withdrawalHash],
});$escape$,
