INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '590a5987-e2de-461f-9bff-ddd2f3fdf714',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Transaction Lifecycle — Mempool, Ordering, Finality, and Reorg Risk$escape$,
  $escape$When you call eth_sendRawTransaction, your signed tx enters the public mempool (txpool). Validators running MEV-Boost pull txs via the builder API — block builders order them to maximize extractable value, not just by gas price. Priority fee (EIP-1559) still influences inclusion, but MEV searchers can sandwich or frontrun you regardless.

Once included in a block, the tx has 1 confirmation. Ethereum's LMD-GHOST + Casper FFG consensus finalizes checkpoints every 2 epochs (~12.8 min). Before finality, a reorg is possible: if a competing fork has more attestation weight, your block can be orphaned and the tx dropped back to the mempool — or lost entirely if the replacement block doesn't include it.

For high-value ops, poll eth_getTransactionReceipt and check block.finalized via eth_getBlockByNumber with tag "finalized". Never treat 1–2 confirmations as safe for irreversible actions. Use Flashbots Protect RPC to bypass the public mempool and reduce frontrun/reorg exposure on sensitive txs.$escape$,
  $escape$import { createPublicClient, http } from 'viem';
import { mainnet } from 'viem/chains';

const client = createPublicClient({ chain: mainnet, transport: http() });

async function awaitFinality(txHash: `0x${string}`) {
  const receipt = await client.waitForTransactionReceipt({ hash: txHash });

  while (true) {
    const finalized = await client.getBlock({ blockTag: 'finalized' });
    if (receipt.blockNumber <= finalized.number) {
      console.log('Tx finalized at block', receipt.blockNumber);
      return receipt;
    }
    await new Promise(r => setTimeout(r, 12_000)); // 1 slot
  }
}$escape$,
  $escape$typescript$escape$,
