INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e8defb99-7d00-471b-b888-ad32ad04f08d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum + Polygon — PoS, zkEVM, AggLayer, and Bridging Assets$escape$,
  $escape$Polygon offers two distinct Ethereum-connected chains: Polygon PoS (a commit-chain using plasma checkpoints + Heimdall validators) and Polygon zkEVM (a Type-2 ZK-equivalent rollup posting validity proofs to Ethereum L1). They are not interchangeable. PoS bridges assets via the FxPortal or the native PoS bridge — locking ERC-20s on Ethereum and minting mapped tokens on PoS. zkEVM uses a canonical bridge where withdrawals require a ZK proof to be verified on L1 before funds unlock, adding a ~30–60min finality window versus PoS's ~7-day challenge period on plasma exits (though PoS MATIC withdrawals via the PoS bridge settle in ~3 hours). AggLayer is Polygon's unified liquidity protocol: chains publish ZK proofs to a single aggregator contract on Ethereum L1, enabling atomic cross-chain transactions without wrapping assets per hop. For production bridging on PoS, use the official `@maticnetwork/maticjs` SDK or call `RootChainManager.depositFor()` on Ethereum directly. Always check the `checkpointManager` sync lag before assuming PoS state is finalized on L1.$escape$,
  $escape$import { ethers } from 'ethers';

// Deposit ERC-20 from Ethereum -> Polygon PoS via RootChainManager
const ROOT_CHAIN_MANAGER = '0xA0c68C638235ee32657e8f720a23ceC1bFc77C77';
const ERC20_PREDICATE  = '0x40ec5B33f54e0E8A33A975908C5BA1c14e5BbbDf';

const abi = ['function depositFor(address user, address rootToken, bytes calldata depositData) external'];

async function depositToPolygon(signer: ethers.Signer, tokenAddress: string, amount: bigint) {
  const token = new ethers.Contract(tokenAddress, ['function approve(address,uint256)'], signer);
  await (await token.approve(ERC20_PREDICATE, amount)).wait();

  const manager = new ethers.Contract(ROOT_CHAIN_MANAGER, abi, signer);
  const depositData = ethers.AbiCoder.defaultAbiCoder().encode(['uint256'], [amount]);
  const tx = await manager.depositFor(await signer.getAddress(), tokenAddress, depositData);
  await tx.wait();
  console.log('Deposit tx:', tx.hash, '— await checkpoint on Polygon PoS (~5-10 min)');
}$escape$,
  $escape$typescript$escape$,
