INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bac683ba-a787-4459-9770-c8d25d0851d4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum EVM Compatibility — Deploy Once, Run Anywhere$escape$,
  $escape$EVM compatibility means a chain executes the same bytecode the Ethereum mainnet does. When you compile a Solidity contract with `solc`, the output is EVM bytecode — a stack-based instruction set (PUSH, MLOAD, SSTORE, CALL, etc.). Any chain that implements the EVM spec (EIP-150, EIP-155, EIP-1559 where adopted) can run that bytecode unchanged.

Chains like Polygon PoS, Arbitrum One, Optimism, Base, Avalanche C-Chain, and BNB Smart Chain all expose an EVM-compatible execution environment. Your Hardhat config only needs a new `networks` entry — same ABI, same ethers.js calls, same event signatures, same `eth_getLogs` RPC.

The catch: EVM-equivalent (like Optimism's Bedrock) ≠ EVM-compatible. Equivalent chains pass the full Ethereum test suite; compatible chains may diverge on precompiles, gas schedules, or opcode costs. Arbitrum, for instance, has a custom `ArbGas` model and added precompiles at `0x0000000000000000000000000000000000000064–0x0068`.

Always check chain-specific differences before assuming 1:1 portability — especially for assembly-heavy contracts using `SELFDESTRUCT`, `PUSH0` (EIP-3855), or `MCOPY` (EIP-5656).$escape$,
  $escape$// hardhat.config.ts — reuse the same contract across EVM chains
import { HardhatUserConfig } from "hardhat/config";

const config: HardhatUserConfig = {
  solidity: "0.8.26",
  networks: {
    mainnet:  { url: process.env.ETH_RPC!,  chainId: 1     },
    arbitrum: { url: process.env.ARB_RPC!,  chainId: 42161 },
    base:     { url: process.env.BASE_RPC!, chainId: 8453  },
    polygon:  { url: process.env.POL_RPC!,  chainId: 137   },
  },
};

export default config;
// npx hardhat run scripts/deploy.ts --network arbitrum$escape$,
  $escape$typescript$escape$,
