INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe13606f-7731-4e01-88fe-3a2388326122',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum MEV — Frontrunning, Sandwich Attacks, and How PBS Reshapes Block Production$escape$,
  $escape$MEV (Maximal Extractable Value) is profit extracted by reordering, inserting, or censoring transactions within a block. On Ethereum, bots monitor the public mempool for high-value opportunities — a large Uniswap V3 swap triggers a sandwich attack: the bot frontruns with a buy on the same pool (pushing price up), lets your tx execute at a degraded rate, then immediately backtrades to pocket the difference. This is pure on-chain arbitrage at your expense.

Post-Merge, Proposer-Builder Separation (PBS) via MEV-Boost decouples block building from validation. Validators (proposers) outsource block construction to specialized builders (Flashbots, BloXroute, Titan) who compete by offering the highest `block.value`. ~90% of Ethereum blocks are now MEV-Boost blocks. Builders aggregate private orderflow and MEV bundles to maximize fees.

To avoid sandwich exposure, submit via Flashbots `eth_sendBundle`: transactions bypass the public mempool, land atomically in a target block, or revert cleanly — no partial fills, no leaked intent. Pair with tight slippage (0.5% stables, 1% volatile pairs) on Uniswap's `exactInputSingle`.$escape$,
  $escape$import { FlashbotsBundleProvider } from '@flashbots/ethers-provider-bundle';
import { ethers } from 'ethers';

const provider = new ethers.JsonRpcProvider(process.env.ETH_RPC_URL);
const authSigner = new ethers.Wallet(process.env.FLASHBOTS_AUTH_KEY!, provider);
const flashbotsProvider = await FlashbotsBundleProvider.create(provider, authSigner);

const bundle = [{
  transaction: { to: UNISWAP_V3_ROUTER, data: swapCalldata,
    gasLimit: 200_000, maxFeePerGas: ethers.parseUnits('30', 'gwei'), chainId: 1 },
  signer: userWallet,
}];

const targetBlock = (await provider.getBlockNumber()) + 1;
const response = await flashbotsProvider.sendBundle(bundle, targetBlock);
if ('error' in response) throw new Error(response.error.message);$escape$,
  $escape$typescript$escape$,
