INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e35d115f-1fd4-4cfc-a00c-60c9fd8a426c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Account Abstraction — ERC-4337 Paymasters and Gasless UX in Practice$escape$,
  $escape$ERC-4337 introduces a parallel mempool for UserOperations — structs that describe intent rather than raw transactions. Instead of an EOA signing a tx, a smart contract wallet (e.g. Safe, Kernel, Biconomy) validates and executes ops via the singleton EntryPoint at 0x5FF137D4b0FDCD49DcA30c7CF57E578a026d2789. The critical unlock for UX is the Paymaster: a contract that sponsors gas on behalf of users. When your UserOperation's paymasterAndData field points to a VerifyingPaymaster, the EntryPoint calls validatePaymasterUserOp, checks an off-chain signature, and debits the paymaster's deposited ETH instead of the user's wallet. This lets you onboard users with zero ETH — they sign a typed UserOperation, your backend cosigns with the paymaster key, and the Bundler (e.g. Pimlico, Alchemy's Rundler) submits to the EntryPoint. Combine with ERC-7579 modular validators and you get session keys, spend limits, and social recovery — all without forking the protocol. The EntryPoint's handleOps call is atomic: all-or-nothing across the entire batch.$escape$,
  $escape$import { createSmartAccountClient, ENTRYPOINT_ADDRESS_V07 } from 'permissionless';
import { createPimlicoPaymasterClient } from 'permissionless/clients/pimlico';
import { signerToSafeSmartAccount } from 'permissionless/accounts';
import { createPublicClient, http } from 'viem';
import { mainnet } from 'viem/chains';

const publicClient = createPublicClient({ chain: mainnet, transport: http() });

const safeAccount = await signerToSafeSmartAccount(publicClient, {
  signer,
  safeVersion: '1.4.1',
  entryPoint: ENTRYPOINT_ADDRESS_V07,
});

const paymasterClient = createPimlicoPaymasterClient({
  transport: http(`https://api.pimlico.io/v2/mainnet/rpc?apikey=${API_KEY}`),
  entryPoint: ENTRYPOINT_ADDRESS_V07,
});

const smartAccountClient = createSmartAccountClient({
  account: safeAccount,
  chain: mainnet,
  bundlerTransport: http(`https://api.pimlico.io/v1/mainnet/rpc?apikey=${API_KEY}`),
  middleware: { sponsorUserOperation: paymasterClient.sponsorUserOperation },
});

// Gas is paid by paymaster — user needs zero ETH
const txHash = await smartAccountClient.sendTransaction({
  to: '0xRecipient',
  value: 0n,
  data: '0x',
});$escape$,
  $escape$typescript$escape$,
