INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81af2ee3-b1de-42e9-be9c-79d005d8283d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum on Base — OP Stack Architecture, Blob Batching, and the Superchain$escape$,
  $escape$Base is Coinbase's Ethereum L2 built on the OP Stack — the same open-source rollup framework powering Optimism Mainnet. It runs op-geth (a patched go-ethereum) for EVM equivalence, meaning existing Solidity contracts, ABIs, and Hardhat/Foundry tooling deploy without modification. Chain ID: 8453 (mainnet), 84532 (Sepolia).

Deposits flow through the OptimismPortal contract on L1 via depositTransaction(). Withdrawals trigger a 7-day fault proof window before funds are claimable on L1 — enforced by the DisputeGameFactory under the fault proof system Base shipped in 2024.

Post-EIP-4844, Base submits transaction batches as blob transactions to the BatchInbox address, cutting data availability costs ~10x versus calldata. The L2OutputOracle has been replaced by a permissioned proposer posting output roots every ~1 hour.

The Superchain vision unifies Base, OP Mainnet, Zora, and Mode under shared fault proofs and a CrossL2Inbox for synchronous cross-chain messaging. Inter-op messages use initiateMessage() / executeMessage() — letting contracts call across OP Stack chains atomically within the cluster without bridging delays.$escape$,
  $escape$import { createWalletClient, http, parseEther } from "viem";
import { mainnet } from "viem/chains";
import { privateKeyToAccount } from "viem/accounts";

// Bridge ETH from Ethereum L1 → Base via OptimismPortal
const OPTIMISM_PORTAL = "0x49048044D57e1C92A77f79988d21Fa8fAF74E97c";

const client = createWalletClient({
  account: privateKeyToAccount(process.env.PRIVATE_KEY as `0x${string}`),
  chain: mainnet,
  transport: http(process.env.L1_RPC_URL),
});

// depositTransaction(to, value, gasLimit, isCreation, data)
const hash = await client.writeContract({
  address: OPTIMISM_PORTAL,
  abi: [{ name: "depositTransaction", type: "function",
    inputs: [{ type: "address" }, { type: "uint256" }, { type: "uint64" }, { type: "bool" }, { type: "bytes" }] }],
  functionName: "depositTransaction",
  args: ["0xRecipientOnBase", parseEther("0.01"), 21000n, false, "0x"],
  value: parseEther("0.01"),
});$escape$,
