INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '247f112c-269f-40c9-8bc1-25bea6eed65b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum NFT Standards — ERC-721 vs ERC-1155 and the Metadata Trap$escape$,
  $escape$ERC-721 mints one token per `tokenId`, making each truly unique. ERC-1155 is a multi-token standard — one contract handles both fungible and non-fungible tokens via `balanceOf(address, id)`, enabling batch transfers with `safeBatchTransferFrom` and dramatically lower gas costs for collections.

Both standards rely on `tokenURI(uint256 tokenId)` returning a URI pointing to a JSON metadata blob. The critical distinction: most production NFTs store this JSON on IPFS or Arweave (off-chain), meaning your on-chain token is a pointer, not the asset. If the IPFS node goes dark, `image` returns a 404.

On-chain metadata — storing base64-encoded SVG or JSON directly in the contract — is immutable and censorship-resistant but expensive. Projects like Nouns DAO and Loot store everything on-chain using `abi.encodePacked` + `Base64.encode`.

For ERC-1155, the metadata URI uses a `{id}` placeholder: `https://api.example.com/token/{id}.json`, which clients replace with the hex-padded token ID. ERC-721's `tokenURI` must be overridden per-token, giving finer-grained control but no batch efficiency.$escape$,
  $escape$// On-chain SVG metadata with ERC-721 (OpenZeppelin)
function tokenURI(uint256 tokenId) public view override returns (string memory) {
    string memory svg = string(abi.encodePacked(
        '<svg xmlns="http://www.w3.org/2000/svg"><text>',
        Strings.toString(tokenId),
        '</text></svg>'
    ));
    string memory json = Base64.encode(bytes(string(abi.encodePacked(
        '{"name":"Token #', Strings.toString(tokenId),
        '","image":"data:image/svg+xml;base64,', Base64.encode(bytes(svg)), '"}'
    ))));
    return string(abi.encodePacked('data:application/json;base64,', json));
}$escape$,
  $escape$solidity$escape$,
