INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7d0d9e27-695c-4b78-b5b1-68b76114c164',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Security — Reentrancy, Oracle Manipulation, and Key Management in Practice$escape$,
  $escape$Three attack vectors drain more ETH than any other. Reentrancy hits when an external contract calls back into yours before state updates — guard every external call with the checks-effects-interactions pattern or OpenZeppelin's ReentrancyGuard. The classic DAO hack exploited exactly this: `withdraw()` sent ETH before zeroing the balance. Oracle manipulation is subtler: on-chain price feeds like a Uniswap V3 pool spot price can be moved in a single block via flash loans. Always use time-weighted average prices (TWAP) via `IUniswapV3Pool.observe()` over at least a 30-minute window, or delegate to Chainlink's `AggregatorV3Interface.latestRoundData()` with staleness checks on `updatedAt`. Private key management is the most underrated risk. Never derive keys client-side with weak entropy, never commit `.env` files, and use hardware wallets or AWS KMS for signing in production. For server-side signing, `ethers.Wallet.fromEncryptedJson()` with a secrets-manager-injected password is the minimum viable safe path.$escape$,
  $escape$import { ethers } from 'ethers';
import { AggregatorV3Interface__factory } from './typechain';

// Chainlink price feed with staleness guard
async function getSafePrice(feedAddress: string, provider: ethers.Provider): Promise<bigint> {
  const feed = AggregatorV3Interface__factory.connect(feedAddress, provider);
  const { answer, updatedAt } = await feed.latestRoundData();
  const stalenessThreshold = 3600n; // 1 hour in seconds
  const now = BigInt(Math.floor(Date.now() / 1000));
  if (now - updatedAt > stalenessThreshold) throw new Error('Stale oracle price');
  return answer;
}$escape$,
  $escape$typescript$escape$,
