INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd1f839af-e4db-4b38-bb07-74cc218f2b93',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Flash Loans — Atomic Liquidations Across Aave v3 and Uniswap v3 in One Transaction$escape$,
  $escape$Flash loans let you borrow any amount from Aave v3's pool with zero collateral, execute arbitrary logic, and repay within the same transaction — or the entire call reverts. The key interface is `IFlashLoanSimpleReceiver`: Aave calls your `executeOperation` callback mid-transaction, passing the borrowed asset, amount, and premium (currently 0.05%). The real power emerges when you chain DeFi primitives atomically. A classic pattern: borrow USDC via flash loan → call `liquidationCall` on an undercollateralized Aave position (receiving discounted WETH) → swap WETH→USDC on Uniswap v3 via `ISwapRouter.exactInputSingle` → repay flash loan + premium → pocket the spread. All within one block, no capital required. On Uniswap v3, the `sqrtPriceLimitX96` parameter lets you bound slippage precisely — critical when your profit margin is 1–3%. Aave's `ADDRESSES_PROVIDER` on mainnet is `0x2f39d218133AFaB8F2B819B1066c7E434Ad94E9e`. Always simulate with `eth_call` before broadcasting; MEV bots front-run profitable liquidations within milliseconds of mempool visibility.$escape$,
  $escape$// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IFlashLoanSimpleReceiver} from "@aave/core-v3/contracts/flashloan/interfaces/IFlashLoanSimpleReceiver.sol";
import {IPoolAddressesProvider} from "@aave/core-v3/contracts/interfaces/IPoolAddressesProvider.sol";
import {IPool} from "@aave/core-v3/contracts/interfaces/IPool.sol";
import {ISwapRouter} from "@uniswap/v3-periphery/contracts/interfaces/ISwapRouter.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract FlashLiquidator is IFlashLoanSimpleReceiver {
    IPool public immutable POOL;
    ISwapRouter public constant ROUTER =
        ISwapRouter(0xE592427A0AEce92De3Edee1F18E0157C05861564);

    constructor(address provider) {
        POOL = IPool(IPoolAddressesProvider(provider).getPool());
    }

    function executeOperation(
        address asset,
        uint256 amount,
        uint256 premium,
        address,
        bytes calldata params
    ) external override returns (bool) {
        (address collateral, address user) = abi.decode(params, (address, address));

        // Step 1: liquidate undercollateralized position, receive discounted collateral
        IERC20(asset).approve(address(POOL), amount);
        POOL.liquidationCall(collateral, asset, user, amount, false);

        // Step 2: swap collateral back to borrowed asset on Uniswap v3
        uint256 colBal = IERC20(collateral).balanceOf(address(this));
        IERC20(collateral).approve(address(ROUTER), colBal);
        ROUTER.exactInputSingle(ISwapRouter.ExactInputSingleParams({
            tokenIn: collateral,
            tokenOut: asset,
            fee: 500,                      // 0.05% pool
            recipient: address(this),
            deadline: block.timestamp,
            amountIn: colBal,
            amountOutMinimum: amount + premium,
            sqrtPriceLimitX96: 0
        }));

        // Step 3: approve repayment (amount + 0.05% premium)
        IERC20(asset).approve(address(POOL), amount + premium);
        return true;
    }

    function triggerFlashLiquidation(
        address asset, uint256 amount, address collateral, address user
    ) external {
        POOL.flashLoanSimple(
            address(this), asset, amount,
            abi.encode(collateral, user), 0
        );
    }
}$escape$,
