INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6cafe61a-0112-4f1a-85ac-7bc9df74294b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Finality — Probabilistic vs Deterministic, and Why Your Deposit Logic Matters$escape$,
  $escape$Post-Merge Ethereum replaced probabilistic finality with cryptoeconomic determinism via Casper FFG. Under PoW, no block was ever truly irreversible — each confirmation just made a reorg exponentially costlier. Exchanges waited 35+ blocks (~7 min) as a heuristic. That's gone.

Now the beacon chain processes checkpoints every epoch (32 slots, ~6.4 min). After two epochs (~12.8 min), a checkpoint is finalized: reverting it requires slashing ≥1/3 of all staked ETH — currently ~11M ETH. That's a cryptoeconomic guarantee, not a statistical one.

Ethereum's JSON-RPC exposes three actionable block tags:
- `latest` — chain tip, can reorg (1–2 block reorgs still occur occasionally post-Merge)
- `safe` — ~2 slots behind latest, extremely unlikely to reorg
- `finalized` — irreversible, ~2 epochs behind

For deposit crediting or bridge state reads, always anchor to `finalized`. For latency-sensitive reads where 12.8 min lag is unacceptable, `safe` is acceptable with documented risk. Never build financial settlement logic on `latest`. Post-Merge mainnet data shows single-slot reorgs are rare but real; multi-slot reorgs are near-zero without a liveness failure.$escape$,
  $escape$import { createPublicClient, http } from "viem";
import { mainnet } from "viem/chains";

const client = createPublicClient({ chain: mainnet, transport: http() });

const [latest, safe, finalized] = await Promise.all([
  client.getBlock({ blockTag: "latest" }),
  client.getBlock({ blockTag: "safe" }),
  client.getBlock({ blockTag: "finalized" }),
]);

console.log(`Latest:    #${latest.number}   (reorg possible)`);
console.log(`Safe:      #${safe.number}   (reorg very unlikely)`);
console.log(`Finalized: #${finalized.number}   (cryptoeconomically irreversible)`);

// For deposit logic: only credit funds once tx block <= finalized.number
const isFinal = (txBlockNumber: bigint) => txBlockNumber <= finalized.number!;$escape$,
  $escape$typescript$escape$,
