INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c8463150-9bd7-4ad0-b6b2-1e68932cac6f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum Nodes Demystified — Full vs Archive vs Light, and Why Public RPCs Are a Risk$escape$,
  $escape$Ethereum nodes aren't interchangeable. Full nodes (Geth, Nethermind) store current world state and a rolling chain history — Geth prunes state beyond ~128 blocks by default. Calling `eth_getBalance` at block 15,000,000 on a full node returns `missing trie node`. For historical state queries, you need an archive node, which stores every state transition since genesis — roughly 18 TB on mainnet today.

Light nodes sync only block headers and outsource state proofs to serving full nodes. Fine for lightweight wallets, not for dApps that need reliable state.

Public RPCs (Infura, Alchemy, QuickNode) hide this complexity but introduce real risks: rate limits that break under load, IP and address correlation that leaks wallet activity, and centralization — Infura's November 2020 outage took down MetaMask and most of DeFi simultaneously. For MEV-sensitive flows, your pending transactions are visible to the RPC provider before broadcast.

Snap sync makes running your own full node practical: syncs in hours, not weeks. For `eth_getLogs` over wide block ranges or replaying historical transactions, spin up an archive node or use a provider that explicitly offers archive access.$escape$,
  $escape$import { createPublicClient, http } from 'viem';
import { mainnet } from 'viem/chains';

// Point to your own node — never leak wallet queries to a third party
const client = createPublicClient({
  chain: mainnet,
  transport: http('http://localhost:8545'),
});

// Works ONLY on archive nodes — full nodes prune this state
// Full node returns: Error: missing trie node
const balance = await client.getBalance({
  address: '0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045',
  blockNumber: 15_000_000n,
});

console.log(`Balance at block 15M: ${balance} wei`);$escape$,
