INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7ce8072-f577-4154-a0ac-3cb0d9dbd482',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ethereum L2 Decision Framework — Arbitrum vs Optimism vs Base vs Polygon$escape$,
  $escape$All four are EVM-compatible, but security models diverge sharply. Arbitrum Nitro and Optimism use fraud proofs with a 7-day challenge window before L1 finality. Base is an OP Stack fork — same security model as Optimism, Coinbase sequencer. Polygon zkEVM uses validity proofs: cryptographic finality, no challenge period. Polygon PoS is a sidechain, not a rollup — bridge security depends on its own validator set, not Ethereum consensus.

Decision axes:
- **DeFi/Liquidity**: Arbitrum — deepest GMX, Uniswap v3, Camelot liquidity.
- **Consumer/AA**: Base — native ERC-4337 infra, Coinbase distribution, Smart Wallet.
- **Superchain/L3**: Optimism — OP Stack lets you launch your own L3 inheriting L1 security.
- **ZK Finality**: Polygon zkEVM — validity proofs, no 7-day withdrawal delay for bridging at scale.
- **Gas**: All chains use EIP-4844 blobs post-Dencun — calldata costs dropped ~10×.

Gate chain-specific logic on `eth_chainId`: Arbitrum One (42161), OP Mainnet (10), Base (8453), Polygon zkEVM (1101).$escape$,
  $escape$import { arbitrum, optimism, base, polygonZkEvm } from 'viem/chains'

const L2_PROFILES = {
  [arbitrum.id]:      { model: 'optimistic', bestFor: 'defi',     withdrawalDays: 7 },
  [optimism.id]:      { model: 'optimistic', bestFor: 'superchain', withdrawalDays: 7 },
  [base.id]:          { model: 'optimistic', bestFor: 'consumer',  withdrawalDays: 7 },
  [polygonZkEvm.id]:  { model: 'zk-validity', bestFor: 'zk-bridge', withdrawalDays: 0 },
} as const

function pickL2(useCase: 'defi' | 'consumer' | 'superchain' | 'zk-bridge') {
  return Object.entries(L2_PROFILES).find(
    ([, p]) => p.bestFor === useCase
  )?.[0]
}$escape$,
